class LongT5LayerNorm(nn.Module)(hidden_size, eps=1e-6) {
  weight = nn.Parameter(1.0 * hidden_size)
  variance_epsilon = eps

  forward(x) = x.to(torch.float32).pow(2).mean(-1, keepdim=True) |> λ: x * (1/√(λ + variance_epsilon)) |> λ: (λ * x).to(weight.dtype if weight.dtype in [float16,bfloat16] else float32)
}
